function f(t){const e=t.getDay();return e!==0&&e!==6}function h(t){const e=new Date(t);for(;!f(e);)e.setDate(e.getDate()+1);return e}function l(t,e){const a=new Date(t,e-1,10);return h(a)}function y(t,e,a,o=15){const r=new Date(a),n=new Date(e);if(r<=n)return{baseAmount:t,surcharge:0,totalAmount:t,appliedSurcharge:!1};const u=n.getFullYear(),i=n.getMonth()+1,D=l(u,i),c=r>D,s=c?t*o/100:0,g=t+s;return{baseAmount:t,surcharge:s,totalAmount:g,appliedSurcharge:c}}function S(t,e){return e==="pagado"?!1:new Date(t)<new Date}function p(t){return(typeof t=="string"?new Date(t):t).toLocaleDateString("es-AR")}export{y as c,p as f,S as i};
